		t.Errorf("~/.codex/AGENTS.md missing managed-section markers:\n%s", cBody)
	}

	// Codex mcp → ~/.codex/config.toml.
	codexConfig := filepath.Join(home, ".codex", "config.toml")
	mustExist(t, codexConfig)
