	home := t.TempDir()
	repo := filepath.Join(home, "a", "b", "c")
	mkGit(t, repo)
	deep := filepath.Join(repo, "d", "e")
	if err := os.MkdirAll(deep, 0o755); err != nil {
		t.Fatalf("mkdir: %v", err)
